-- =====================================================================
-- alimento_seed.sql  —  SEED CONSOLIDATO e BONIFICATO
-- Stato finale dopo i fix 02->07 (categorie, unità, pesi, nutrienti,
-- inserimenti, alias). Validato con una passata completa di QA (tutti i controlli PASS).
-- Righe: 1388.  Idempotente: INSERT ... ON CONFLICT ("Nome") DO UPDATE.
-- Richiede che la tabella "alimento" esista gia' (schema invariato).
--
-- MIGRAZIONE IN-PLACE (sostituisce il seed precedente, 1382 righe) —
-- SICURA PER I PASTI GIA' REGISTRATI:
--  * Upsert per "Nome" (chiave naturale): le 1382 righe esistenti vengono
--    AGGIORNATE conservando il loro "IdAlimento" → nessuna FK rotta su
--    alimento_pasto.IdAlimento (ON UPDATE CASCADE). I 6 nuovi alimenti
--    ricevono un IdAlimento nuovo dalla sequence.
--  * Nessun DELETE/TRUNCATE: nessuna riga rimossa, nessun pasto perso.
--  * I pasti storici restano invariati: alimento_pasto memorizza i propri
--    valori *Calc (snapshot del trigger all'inserimento, mai ricalcolati),
--    quindi modificare "alimento" non altera i diari gia' salvati. I nuovi
--    pasti useranno i valori aggiornati.
-- Eseguibile direttamente nell'SQL Editor di Supabase (un'unica transazione;
-- in caso di errore l'intero blocco viene annullato).
-- =====================================================================
BEGIN;

CREATE UNIQUE INDEX IF NOT EXISTS alimento_nome_uidx ON alimento ("Nome");

ON CONFLICT ("Nome") DO UPDATE SET
  "Alias"                  = EXCLUDED."Alias",
  "Categoria"              = EXCLUDED."Categoria",
  "LattosioP100g"          = EXCLUDED."LattosioP100g",
  "SorbitoloP100g"         = EXCLUDED."SorbitoloP100g",
  "GlutineP100g"           = EXCLUDED."GlutineP100g",
  "CaloriePer100g"         = EXCLUDED."CaloriePer100g",
  "ConversioniUnitaMisura" = EXCLUDED."ConversioniUnitaMisura",
  "FonteDati"              = EXCLUDED."FonteDati";

-- Reset esplicito della sequenza IdAlimento (next nextval = MAX+1).
SELECT setval(
  pg_get_serial_sequence('alimento','IdAlimento'),
  (SELECT COALESCE(MAX("IdAlimento"), 1) FROM alimento),
  true
);

-- Sanity-check (annulla la transazione se falliscono):
--  1) il dataset deve contenere almeno le 1388 voci attese;
--  2) nessuna chiave "g" in ConversioniUnitaMisura (il grammo è l'unità base
--     implicita, vedi NOTA sotto e docs/architecture.md §"Dataset alimentare").
DO $$
DECLARE
  v_count bigint;
  v_g     bigint;
BEGIN
  SELECT count(*) INTO v_count FROM alimento;
  IF v_count < 1388 THEN
    RAISE EXCEPTION 'Sanity-check fallito: attese >= 1388 voci in alimento, trovate %', v_count;
  END IF;

  SELECT count(*) INTO v_g FROM alimento WHERE "ConversioniUnitaMisura" ? 'g';
  IF v_g > 0 THEN
    RAISE EXCEPTION 'Sanity-check fallito: % righe contengono la chiave "g" (vietata)', v_g;
  END IF;
END $$;

COMMIT;

-- NOTA: ConversioniUnitaMisura NON contiene la chiave "g". Il grammo è l'unità
-- base implicita (tutte le colonne *P100g sono per 100g, QuantitaGrammi è in
-- grammi), quindi la chiave sarebbe ridondante; il client antepone "g" come
-- prima opzione canonica in Food.availableUnits(). Le INSERT sopra nascono già
-- prive di "g" (nessuno strip post-insert: il dataset è corretto alla fonte).

-- Verifica finale (read-only): conteggio per fonte dati.
SELECT count(*) AS totale_alimenti FROM alimento;

-- In caso di errore durante l'esecuzione, lancia manualmente:  ROLLBACK;